#include "controller.h"

#include <string.h>

static void controller_set_safe_vent(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller->compressor_on = false;
    controller->vent_open = true;
    controller->state = CONTROLLER_STATE_SAFE_VENT;
}

void controller_init(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller_set_safe_vent(controller);
    controller->has_valid_pressure = false;
    controller->last_pressure_kpa = 0;
    controller->last_pressure_ms = 0U;
    controller->has_valid_door = false;
    controller->door_closed = false;
    controller->last_door_ms = 0U;
}

static bool controller_check_timeout(controller_t *controller, uint32_t now_ms)
{
    if (controller == NULL) {
        return false;
    }

    const uint32_t PRESSURE_TIMEOUT_MS = CONTROLLER_SENSOR_TIMEOUT_MS;
    const uint32_t DOOR_TIMEOUT_MS = CONTROLLER_SENSOR_TIMEOUT_MS;

    bool pressure_stale = !controller->has_valid_pressure || 
                          (now_ms - controller->last_pressure_ms) > PRESSURE_TIMEOUT_MS;
    bool door_stale = !controller->has_valid_door || 
                      (now_ms - controller->last_door_ms) > DOOR_TIMEOUT_MS;

    return pressure_stale || door_stale;
}

static void controller_apply_control_policy(controller_t *controller, bool door_closed, int pressure_kpa)
{
    if (controller == NULL) {
        return;
    }

    /* 
     * Control policy:
     * - If door is open: SAFE_VENT (compressor OFF, vent OPEN)
     * - If door is closed and PRESS < 40: COMPRESSOR ON, VENT CLOSED
     * - If door is closed and PRESS > 60: COMPRESSOR OFF, VENT OPEN
     * - If door is closed and 40 <= PRESS <= 60: hold previous safe output
     */

    if (!door_closed) {
        /* Door open - safe vent state */
        controller->compressor_on = false;
        controller->vent_open = true;
        controller->state = CONTROLLER_STATE_SAFE_VENT;
    } else if (pressure_kpa < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
        /* Low pressure - pressurize */
        controller->compressor_on = true;
        controller->vent_open = false;
        controller->state = CONTROLLER_STATE_PRESSURIZING;
    } else if (pressure_kpa > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
        /* High pressure - relieve */
        controller->compressor_on = false;
        controller->vent_open = true;
        controller->state = CONTROLLER_STATE_RELIEVING;
    } else {
        /* In holding band - preserve previous safe output */
        /* Do not change compressor or vent state, just update state to HOLDING */
        controller->state = CONTROLLER_STATE_HOLDING;
    }
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .compressor_on = false,
        .vent_open = true,
        .state = CONTROLLER_STATE_SAFE_VENT,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_VENT),
        .changed = false,
        .timed_out = false,
    };

    bool previous_compressor_on;
    bool previous_vent_open;
    controller_state_t previous_state;

    if (controller == NULL) {
        return output;
    }

    previous_compressor_on = controller->compressor_on;
    previous_vent_open = controller->vent_open;
    previous_state = controller->state;

    /* 
     * Process input and update sensor freshness
     */
    switch (input.kind) {
    case CONTROLLER_INPUT_PRESSURE:
        controller->has_valid_pressure = true;
        controller->last_pressure_kpa = input.pressure_kpa;
        controller->last_pressure_ms = input.now_ms;
        break;

    case CONTROLLER_INPUT_DOOR_OPEN:
        controller->has_valid_door = true;
        controller->door_closed = false;
        controller->last_door_ms = input.now_ms;
        break;

    case CONTROLLER_INPUT_DOOR_CLOSED:
        controller->has_valid_door = true;
        controller->door_closed = true;
        controller->last_door_ms = input.now_ms;
        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_PRESSURE:
    case CONTROLLER_INPUT_INVALID_DOOR:
        /* Invalidate both sensors - forces safe vent */
        controller->has_valid_pressure = false;
        controller->has_valid_door = false;
        break;

    case CONTROLLER_INPUT_NONE:
    default:
        /* No new sensor data - check for timeout */
        break;
    }

    /* Check if either sensor has timed out */
    bool timed_out = controller_check_timeout(controller, input.now_ms);
    output.timed_out = timed_out;

    if (timed_out) {
        /* Timeout forces safe vent state */
        controller_set_safe_vent(controller);
    } else {
        /* Apply control policy based on current sensor state */
        controller_apply_control_policy(
            controller,
            controller->door_closed,
            controller->has_valid_pressure ? controller->last_pressure_kpa : 0
        );
    }

    output.compressor_on = controller->compressor_on;
    output.vent_open = controller->vent_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_compressor_on != controller->compressor_on) ||
        (previous_vent_open != controller->vent_open) ||
        (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_PRESSURIZING:
        return "STATE PRESSURIZING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_RELIEVING:
        return "STATE RELIEVING";
    case CONTROLLER_STATE_SAFE_VENT:
    default:
        return "STATE SAFE_VENT";
    }
}

